    public void printAllGenes(String dna){
        int startIndex = 0;
        while(true){
            String currentGene = findGene(dna, startIndex);
            if(currentGene.isEmpty()){
                break;
            }
            System.out.println(currentGene);
            startIndex = dna.indexOf(currentGene, startIndex) + 
                         currentGene.length();
        }
    }
    
    public StorageResource getAllGenes(String dna){
        StorageResource geneList = new StorageResource();
        int startIndex = 0;
        while(true){
            String currentGene = findGene(dna, startIndex);
            if(currentGene.isEmpty()){
                break;
            }
            geneList.add(currentGene);
            startIndex = dna.indexOf(currentGene, startIndex) + 
                         currentGene.length();
        }
        return geneList;
    }
        
    public double cgRatio(String dna){
        int startIndexC = 0;
        double count = 0.0;
        for(int i=startIndexC; i<=dna.length(); i++){
            int curIndex = dna.indexOf("C", i);
            if(curIndex != -1){
                count +=1;
                i=curIndex;
            }
        }
        int startIndexG = 0;
        for(int i=startIndexG; i<=dna.length(); i++){
            int curIndex = dna.indexOf("G", i);
            if(curIndex != -1){
                count +=1;
                i=curIndex;
            }
        }
        double cgratio = count/(dna.length());
        return cgratio;
    }
        
    public int countCTG(String dna){
        int startIndex = 0;
        int count = 0;
        for(int i=startIndex; i<=dna.length(); i++){
            int curIndex = dna.indexOf("CTG", i);
            if(curIndex != -1){
                count += 1;
                i = curIndex + 2;
            }
        }
        return count;
    }
    
    public void processGenes(StorageResource sr){
        int count = 0;
        int c = 0;
        System.out.println("Strings longer than 60 charactors: ");
        for(String s: sr.data()){
            if(s.length()>60){
                System.out.println(s);
                count += 1;
                c+=1;
            }else{
                c+=1;
            }
        }
        System.out.println("No.of all the genes = " + c);
        System.out.println("No. of strings in sr that are longer than 9 charactors = " + count);
        System.out.println("Strings, whose cg ratio is higher than 0.35: ");
        int count2 = 0;
        for(String s: sr.data()){
            double cg = cgRatio(s);
            if(cg > 0.35){
                System.out.println(s);
                count2 += 1;
            }
        
        }
        System.out.println("No. of strings in sr that have cg ratio higher than 0.35 = " + count2);       
        int maxLen = 0;
        String maxString = "";
        for(String s: sr.data()){
            int len = s.length();
            if(len >= maxLen){
                maxLen = len;
                maxString = s;
            }
        }
        System.out.println("Longest gene is " + maxString);
        System.out.println("Length of the longest gene = " + maxLen);
    }
    
